// Detect the WebBLE Safari Web Extension on iPhone at runtime.
// Standard surface: navigator.bluetooth (present on every browser with WebBLE or native support).
// Premium surface: window.webbleIOS (present only on iPhone + WebBLE companion app).
const hasStandardBluetooth = typeof navigator !== 'undefined' && 'bluetooth' in navigator;
const hasPremiumIOS = typeof window !== 'undefined' && 'webbleIOS' in window;

if (hasStandardBluetooth) {
  const available = await navigator.bluetooth.getAvailability();
  console.log('navigator.bluetooth available:', available);
}

if (hasPremiumIOS) {
  const caps = await window.webbleIOS.getCapabilities();
  console.log('WebBLE iOS capabilities:', caps);
} else {
  // Standard surface only — peripheral mode, background sync, beacons, and notifications are unavailable.
}
